### 3. **Expected Services, Use Cases, and Entities**

**Entity Structure** (Domain Layer):

```kotlin
@Entity
@Table(name = "notification")
data class NotificationEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(nullable = false)
    val userId: String = "",

    @Column(nullable = false)
    val title: String = "",

    @Column(nullable = false, columnDefinition = "TEXT")
    val content: String = "",

    @Column(nullable = false)
    val type: Int = 0,  // NotificationType enum value

    @Column(nullable = false)
    val isRead: Boolean = false,

    @Column(nullable = false)
    val createdAt: LocalDateTime = LocalDateTime.now(),

    @Column(nullable = false)
    val updatedAt: LocalDateTime = LocalDateTime.now(),

    @Column(nullable = true)
    val deletedAt: LocalDateTime? = null,
)

enum class NotificationType(val value: Int) {
    CALL(0),
    MESSAGE(1),
    LIKE(2),
    PROMOTION(3),
    SYSTEM(4);

    companion object {
        fun fromValue(value: Int) = entries.first { it.value == value }
    }
}
```

**Repository** (Domain Layer):

```kotlin
interface NotificationRepository : JpaRepository<NotificationEntity, String>, CustomNotificationRepository

interface CustomNotificationRepository {
    fun findByUserIdOrderByCreatedAtDesc(userId: String): List<NotificationEntity>
    fun findByUserIdAndIsReadFalse(userId: String): List<NotificationEntity>
    fun findUnreadCount(userId: String): Long
}
```

**Service** (Notification Module):

```kotlin
@Service
class NotificationService(
    private val repository: NotificationRepository,
) {
    @Transactional(readOnly = true)
    fun getNotification(id: String): NotificationEntity {
        return repository.findById(id)
            .orElseThrow { NotFoundException("Notification not found: $id") }
    }

    @Transactional(readOnly = true)
    fun listNotifications(userId: String, limit: Int, offset: Int): Pair<List<NotificationEntity>, Long> {
        val notifications = repository.findByUserIdOrderByCreatedAtDesc(userId)
        val total = notifications.size.toLong()
        return notifications.drop(offset).take(limit) to total
    }

    @Transactional
    fun createNotification(userId: String, title: String, content: String, type: Int): NotificationEntity {
        val entity = NotificationEntity(
            userId = userId,
            title = title,
            content = content,
            type = type,
            isRead = false,
        )
        return repository.save(entity)
    }

    @Transactional
    fun markAsRead(id: String): Boolean {
        val entity = repository.findById(id).orElseThrow()
        entity.isRead = true
        entity.updatedAt = LocalDateTime.now()
        repository.save(entity)
        return true
    }

    @Transactional
    fun deleteNotification(id: String): Boolean {
        val entity = repository.findById(id).orElseThrow()
        entity.deletedAt = LocalDateTime.now()
        repository.save(entity)
        return true
    }
}
```

