```kotlin
@Controller
class NotificationController(
    private val notificationService: NotificationService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun notification(
        @Argument notificationId: String,
    ): NotificationResponse {
        val response = notificationService.getNotification(notificationId)
        return response.notification.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun notifications(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): NotificationListResponse {
        val response = notificationService.listNotifications(
            userId, 
            limit ?: 20, 
            offset ?: 0
        )
        return NotificationListResponse(
            notifications = response.notificationsList.map { it.toResponse() },
            totalCount = response.totalCount,
        )
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun markNotificationAsRead(
        @Argument notificationId: String,
    ): Boolean {
        return notificationService.markAsRead(notificationId)
    }
}
```

