**Service Tests** (`notification/src/test/kotlin/com/maum/backend/service/`):

```kotlin
@ExtendWith(MockitoExtension::class)
class NotificationServiceTest {
    @Mock
    private lateinit var repository: NotificationRepository

    @InjectMocks
    private lateinit var service: NotificationService

    @Test
    fun `should return notifications by userId`() {
        val userId = "test-user"
        val entities = listOf(
            NotificationEntity(
                id = "1",
                userId = userId,
                title = "Test",
                content = "Test content",
                type = NotificationType.MESSAGE.value,
                isRead = false,
            )
        )
        `when`(repository.findByUserIdOrderByCreatedAtDesc(userId)).thenReturn(entities)

        val (result, total) = service.listNotifications(userId, 20, 0)

        assertThat(result).hasSize(1)
        assertThat(total).isEqualTo(1)
        verify(repository).findByUserIdOrderByCreatedAtDesc(userId)
    }

    @Test
    fun `should mark notification as read`() {
        val id = "1"
        val entity = NotificationEntity(id = id, isRead = false)
        `when`(repository.findById(id)).thenReturn(Optional.of(entity))
        `when`(repository.save(any())).thenReturn(entity.copy(isRead = true))

        val result = service.markAsRead(id)

        assertThat(result).isTrue()
    }
}
```

